object UrlFetcher extends App {
  implicit val system = ActorSystem("UrlFetcher")
  implicit val executor: ExecutionContextExecutor = system.dispatcher
  implicit val materializer = ActorMaterializer()

  val route = akka.http.scaladsl.server.Route {
    case POST(Entity(content, ContentTypes.`application/json`)) =>
      content.toStrict(30.seconds) match {
        case Right(bodyJson) =>
